'use client'

import * as React from 'react'
import { cn } from '../../utils/cn'

export interface CursorFollowProps {
  /** 光标直径（像素） */
  size?: number
  /** 光标颜色 */
  color?: string
  /** 混合模式 */
  blendMode?: 'normal' | 'difference' | 'exclusion' | 'screen'
  /** 是否显示拖尾 */
  trail?: boolean
  /** 拖尾长度 */
  trailLength?: number
  /** 在移动端禁用 */
  disableOnMobile?: boolean
  /** z-index */
  zIndex?: number
  /** 自定义 className */
  className?: string
}

/**
 * CursorFollow - 鼠标跟随自定义光标
 *
 * 默认隐藏系统光标，使用一个圆点跟随鼠标移动。
 * 支持拖尾、混合模式、移动端自动禁用。
 *
 * 注意：此组件会自动给 body 添加 cursor: none 样式，
 * 如需在某些元素保留光标，给该元素加 class="cursor-auto" 即可。
 */
export function CursorFollow({
  size = 24,
  color = '#ffffff',
  blendMode = 'difference',
  trail = false,
  trailLength = 8,
  disableOnMobile = true,
  zIndex = 9999,
  className,
}: CursorFollowProps) {
  const [position, setPosition] = React.useState({ x: 0, y: 0 })
  const [trails, setTrails] = React.useState<Array<{ x: number; y: number; id: number }>>([])
  const [isMobile, setIsMobile] = React.useState(false)
  const [enabled, setEnabled] = React.useState(false)
  const idRef = React.useRef(0)

  // 检测移动端
  React.useEffect(() => {
    if (disableOnMobile) {
      const checkMobile = () => {
        setIsMobile(window.matchMedia('(pointer: coarse)').matches)
      }
      checkMobile()
      window.addEventListener('resize', checkMobile)
      return () => window.removeEventListener('resize', checkMobile)
    }
  }, [disableOnMobile])

  // 控制 body 样式
  React.useEffect(() => {
    if (isMobile) return
    document.body.style.cursor = 'none'
    setEnabled(true)
    return () => {
      document.body.style.cursor = ''
    }
  }, [isMobile])

  // 监听鼠标移动
  React.useEffect(() => {
    if (!enabled) return
    const onMove = (e: MouseEvent) => {
      setPosition({ x: e.clientX, y: e.clientY })
      if (trail) {
        idRef.current += 1
        const id = idRef.current
        setTrails((prev) => [...prev.slice(-(trailLength - 1)), { x: e.clientX, y: e.clientY, id }])
        setTimeout(() => {
          setTrails((prev) => prev.filter((t) => t.id !== id))
        }, 500)
      }
    }
    window.addEventListener('pointermove', onMove)
    return () => window.removeEventListener('pointermove', onMove)
  }, [enabled, trail, trailLength])

  if (isMobile || !enabled) return null

  return (
    <>
      {trail &&
        trails.map((t, i) => (
          <div
            key={t.id}
            className="pointer-events-none fixed rounded-full"
            style={{
              left: t.x - size / 2,
              top: t.y - size / 2,
              width: size * (i / trails.length),
              height: size * (i / trails.length),
              backgroundColor: color,
              opacity: (i / trails.length) * 0.3,
              mixBlendMode: blendMode,
              zIndex: zIndex - 1,
              transition: 'opacity 0.3s, width 0.3s, height 0.3s',
            }}
          />
        ))}
      <div
        className={cn(
          'pointer-events-none fixed rounded-full transition-transform duration-100 ease-out',
          className
        )}
        style={{
          left: position.x - size / 2,
          top: position.y - size / 2,
          width: size,
          height: size,
          backgroundColor: color,
          mixBlendMode: blendMode,
          zIndex,
        }}
      />
    </>
  )
}

'use client'

import { CursorFollow } from './index'
import { useState } from 'react'
import { Label } from '../../_internal/label'

/**
 * CursorFollow 的文档站演示
 * - 默认展示基础效果
 * - 提供控制面板切换 blendMode、trail
 */
export function CursorFollowDemo() {
  const [blendMode, setBlendMode] = useState<'difference' | 'exclusion' | 'screen' | 'normal'>('difference')
  const [trail, setTrail] = useState(false)
  const [color, setColor] = useState('#ffffff')

  return (
    <div className="relative min-h-[400px] w-full bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 p-8">
      <CursorFollow color={color} blendMode={blendMode} trail={trail} />

      <div className="relative z-10 mx-auto max-w-md rounded-xl border border-white/10 bg-black/30 p-6 backdrop-blur-md">
        <h3 className="mb-2 text-lg font-semibold text-white">移动鼠标试试</h3>
        <p className="mb-4 text-sm text-white/70">
          自定义光标会跟随你的鼠标移动。支持拖尾和多种混合模式。
        </p>

        <div className="space-y-3">
          <div>
            <Label className="text-white/80">混合模式</Label>
            <div className="mt-1 flex flex-wrap gap-2">
              {(['difference', 'exclusion', 'screen', 'normal'] as const).map((mode) => (
                <button
                  key={mode}
                  onClick={() => setBlendMode(mode)}
                  className={`rounded-md px-3 py-1 text-xs font-medium transition ${
                    blendMode === mode
                      ? 'bg-white text-black'
                      : 'bg-white/10 text-white/70 hover:bg-white/20'
                  }`}
                >
                  {mode}
                </button>
              ))}
            </div>
          </div>

          <div>
            <Label className="text-white/80">颜色</Label>
            <div className="mt-1 flex gap-2">
              {['#ffffff', '#ff006e', '#06ffa5', '#ffbe0b'].map((c) => (
                <button
                  key={c}
                  onClick={() => setColor(c)}
                  className={`h-6 w-6 rounded-full border-2 ${
                    color === c ? 'border-white scale-110' : 'border-white/30'
                  }`}
                  style={{ backgroundColor: c }}
                />
              ))}
            </div>
          </div>

          <label className="flex items-center gap-2 text-sm text-white/80">
            <input
              type="checkbox"
              checked={trail}
              onChange={(e) => setTrail(e.target.checked)}
              className="h-4 w-4"
            />
            启用拖尾效果
          </label>
        </div>
      </div>
    </div>
  )
}
